komodor:index/action:Action.description:
Creates a new Komodor RBAC action

## Example Usage

<!--Start PulumiCodeChooser -->
```typescript
import * as pulumi from "@pulumi/pulumi";
import * as komodor from "@pulumi/komodor";

const komo_example_pod_viewer = new komodor.Action("komo-example-pod-viewer", {
    action: "pod-viewer",
    description: "View pods",
    ruleset: `[
  {
    \\"apiGroups\\": [
      \\"apps\\"
    ],
    \\"resources\\": [
      \\"pods\\"
    ],
    \\"verbs\\": [
      \\"get\\",
      \\"list\\"
    ]
  }
]
`,
});
const komo_example_policy = new komodor.Policy("komo-example-policy", {
    name: "komo-example-policy",
    statements: pulumi.interpolate`[{
  \"actions\": [
    \"${komo_example_pod_viewer.action}\"
  ],
  \"resources\": [{
    \"cluster\": \"komo-example-cluster\",
    \"namespaces\": [
      \"default\",
      \"kube-system\"
    ]
  }]
}]
`,
});
```
